const (
	ERR_INVALID_ARGUMENT        int32 = 1
	ERR_NO_SUCH_ID              int32 = 2
	ERR_MAX_GROUP_COUNT_REACHED int32 = 3
)

// Outlet group manager interface
type OutletGroupManager interface {
	idl.Object

	// Create a new outlet group.
	//
	//	@param name     New group name
	//	@param members  List of member outlets
	//	@param group    Result: Reference to newly created group; null in case of error
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	//	@return 3 if the maximum number of groups has been reached
	CreateGroup(ctx context.Context, name string, members []outlet.Outlet) (ret int32, group outletgroup.OutletGroup, err error)

	// Retrieve the list of outlet groups.
	//
	//	@return Map of outlet groups, indexed by group ID
	GetAllGroups(ctx context.Context) (map[int32]outletgroup.OutletGroup, error)

	// Retrieve a specific outlet group.
	//
	//	@param id     The ID of the requested group
	//	@param group  Result: requested outlet group; null if not found
	//
	//	@return 0 if OK
	//	@return 2 if no group with the given ID exists
	GetGroup(ctx context.Context, id int32) (ret int32, group outletgroup.OutletGroup, err error)

	// Delete an outlet group.
	//
	//	@param id  The ID of the group to delete
	//
	//	@return 0 if OK
	//	@return 2 if no group with the given ID exists
	DeleteGroup(ctx context.Context, id int32) (int32, error)
}

// Event: A new outlet group has been created
type GroupCreatedEvent interface {
	userevent.UserEvent
	// The ID under which the outlet group manager
	// references this group; may be reused after
	// a group is deleted.
	Id() int32
	UniqueId() int32                // Random ID uniquely identifying the new group
	Group() outletgroup.OutletGroup // The new group
	Settings() outletgroup.Settings // The new group's settings
	isGroupCreatedEvent()
}

// Event: An outlet group has been deleted
type GroupDeletedEvent interface {
	userevent.UserEvent
	// The ID under which the outlet group manager
	// referenced the group
	Id() int32
	UniqueId() int32                // Random unique ID of the deleted group
	Settings() outletgroup.Settings // Last group settings before deletion
	isGroupDeletedEvent()
}
